class MessageValidator:
    def __init__(self, secret_key: Optional[str] = None):
        self.secret_key = secret_key.encode() if secret_key else None
    
    def validate_signature(self, message: bytes, signature: str) -> bool:
        if not self.secret_key:
            return True
        expected_signature = hmac.new(
            self.secret_key,
            message,
            hashlib.sha256
        ).hexdigest()
        return hmac.compare_digest(expected_signature, signature)
    
    def validate_transaction_schema(self, transaction: Dict[str, Any]) -> bool:
        required_fields = ['transaction_id', 'amount', 'timestamp', 'type']
        if not all(field in transaction for field in required_fields):
            return False
        
        if not isinstance(transaction.get('amount'), (int, float)):
            return False
        
        if transaction.get('amount', 0) < 0:
            return False
        
        if not isinstance(transaction.get('transaction_id'), str):
            return False
        
        allowed_types = ['deposit', 'withdrawal', 'transfer', 'payment']
        if transaction.get('type') not in allowed_types:
            return False
        
        return True


class SecureDeserializer:
    ALLOWED_MODULES = {
        'builtins',
        'datetime',
        'decimal',
    }
    
    ALLOWED_CLASSES = {
        'dict', 'list', 'str', 'int', 'float', 'bool', 'NoneType',
        'datetime', 'date', 'Decimal'
    }
    
    @staticmethod
    def deserialize_json(data: bytes) -> Dict[str, Any]:
        try:
            return json.loads(data.decode('utf-8'))
        except (json.JSONDecodeError, UnicodeDecodeError) as e:
            logger.error(f"JSON deserialization error: {e}")
            raise ValueError("Invalid JSON format")
    
    @staticmethod
    def deserialize_pickle_safe(data: bytes) -> Any:
        class RestrictedUnpickler(pickle.Unpickler):
            def find_class(self, module, name):
                if module not in SecureDeserializer.ALLOWED_MODULES:
                    raise pickle.UnpicklingError(
                        f"Module {module} not allowed for deserialization"
                    )
                if name not in SecureDeserializer.ALLOWED_CLASSES:
                    raise pickle.UnpicklingError(
                        f"Class {name} not allowed for deserialization"
                    )
                return super().find_class(module, name)
        
        try:
            return RestrictedUnpickler(pickle.BytesIO(data)).load()
        except (pickle.UnpicklingError, AttributeError, EOFError) as e:
            logger.error(f"Pickle deserialization error: {e}")
            raise ValueError("Invalid or unsafe pickle data")


class TransactionHandler:
    def __init__(self):
        self.handlers: Dict[str, Callable] = {}
    
    def register_handler(self, transaction_type: str, handler: Callable):
        if not callable(handler):
            raise ValueError("Handler must be callable")
        self.handlers[transaction_type] = handler
    
    def handle(self, transaction: Dict[str, Any]) -> bool:
        transaction_type = transaction.get('type')
        if transaction_type not in self.handlers:
            logger.warning(f"No handler registered for type: {transaction_type}")
            return False
        
        try:
            handler = self.handlers[transaction_type]
            handler(transaction)
            return True
        except Exception as e:
            logger.error(f"Error executing handler for {transaction_type}: {e}")
            return False


